CODE_EXAMPLE:
// Prefer positive predicate
if (buffer.isEmpty()) {
    process(buffer);
}

if (user.isAuthenticated()) {
    allowAccess();
} else {
    redirect();
}

// Encapsulate when the condition is complex
private boolean shouldSkip(Item item) {
    return item.isExpired() || item.isDeleted();
}

UNIT_TEST_EXAMPLE:
@Test
public void isEmpty_returnsTrueForNewBuffer() {
    Buffer buf = new Buffer();
    assertTrue(buf.isEmpty());
}

@Test
public void isEmpty_returnsFalseAfterWrite() {
    Buffer buf = new Buffer();
    buf.write("data");
    assertFalse(buf.isEmpty());
}
